def payroll_data(item):return{"id":item.id,"employee_id":item.employee_id,"employee_name":f"{item.employee.first_name} {item.employee.last_name}".strip(),"employee_code":item.employee.employee_code,"month":item.payroll_period.name,"basic_salary":float(item.basic_salary),"bonus":float(item.bonus+item.total_allowance),"deductions":float(item.total_deduction+item.tax_amount),"net_pay":float(item.net_salary),"status":item.payment_status}
def component_data(x):return{"id":x.id,"name":x.name,"code":x.code,"component_type":x.component_type,"calculation_type":x.calculation_type,"value":float(x.default_amount),"is_taxable":x.is_taxable,"is_active":x.is_active,"description":x.description}
def cycle_data(x):return{"id":x.id,"name":x.name,"frequency":x.frequency,"pay_day":x.pay_day,"is_default":x.is_default,"is_active":x.is_active}
def tax_data(x):return{"id":x.id,"min_income":float(x.min_income),"max_income":float(x.max_income)if x.max_income is not None else None,"rate":float(x.rate),"description":x.description,"is_active":x.is_active}
def policy_data(x):return{"id":x.id,"name":x.name,"category":x.category,"count_type":x.count_type,"policy_type":x.policy_type,"considerable_value":float(x.considerable_value),"adjusted_value":float(x.adjusted_value),"value_mode":x.value_mode,"description":x.description,"is_active":x.is_active}
